      "kind": "Statement",
      "metadata": {
        "creationTimestamp": "2025-07-24T16:43:47.036Z",
        "name": "stmt-1",
        "uid": "a827600e-fca9-4fd7-a047-2728f263269d",
        "updateTimestamp": "2025-07-24T16:43:47.036Z"
