    CREATE TABLE `customer_changes` (
      `key` VARBINARY(2147483647),
       `id` INT NOT NULL,
       `name` VARCHAR(2147483647) NOT NULL,
       `email` VARCHAR(2147483647) NOT NULL
    )
    DISTRIBUTED BY HASH(`key`) INTO 6 BUCKETS
    WITH (
      'changelog.mode' = 'retract',
